import React, { useEffect, useState } from "react";
import "./Checkout.css";
import { Link, useNavigate } from "react-router-dom";
import axios from "axios";
import Footer from "./Footer";

function Checkout() {
  const navigate = useNavigate();
  const [cart, setCart] = useState([]);

  const [form, setForm] = useState({
    name: "",
    phone: "",
    email: "",
    address: "",
    city: "",
    pincode: "",
    paymentMethod: "COD",
  });

  const adminPhone = "91xxxxxxxxxx"; // <-- ungal WhatsApp number (country code oda)

  // Load cart
  useEffect(() => {
    const stored = JSON.parse(localStorage.getItem("cart") || "[]");
    setCart(stored);
  }, []);

  // Totals
  const total = cart.reduce((sum, it) => sum + it.price * it.quantity, 0);
  const delivery = total > 999 || total === 0 ? 0 : 49;
  const grandTotal = total + delivery;

  // Form change
  const onChange = (e) => {
    const { name, value } = e.target;
    setForm((f) => ({ ...f, [name]: value }));
  };

  // Validate
  const validate = () => {
    if (!form.name.trim()) return "Enter name";
    if (!/^\d{10}$/.test(form.phone)) return "Enter valid 10-digit phone";
    if (!/^\S+@\S+\.\S+$/.test(form.email)) return "Enter valid email";
    if (!form.address.trim()) return "Enter address";
    if (!form.city.trim()) return "Enter city";
    if (!/^[1-9][0-9]{5}$/.test(form.pincode)) return "Enter valid pincode";
    if (cart.length === 0) return "Cart empty";
    return null;
  };

  // Save Order + WhatsApp
  const saveOrder = async (paymentStatus, razorpayId = null) => {
    const orderId = "ORD" + Date.now();

    const order = {
      orderId,
      customer: {
        name: form.name,
        phone: form.phone,
        email: form.email,
        address: `${form.address}, ${form.city} - ${form.pincode}`,
      },
      items: cart,
      totals: { total, delivery, grandTotal },
      paymentMethod: form.paymentMethod,
      paymentStatus,
      razorpayId,
      status: "Pending",
      createdAt: new Date().toISOString(),
    };

    // 1. Save to backend
    await axios.post("http://localhost:5000/api/orders", order);

    // 2. WhatsApp message
    const msg = `🛍️ New Order!\n\nOrder ID: ${orderId}\nName: ${form.name}\nPhone: ${form.phone}\nEmail: ${form.email}\nTotal: ₹${grandTotal}\nAddress: ${form.address}, ${form.city} - ${form.pincode}`;
    const whatsappURL = `https://wa.me/${adminPhone}?text=${encodeURIComponent(msg)}`;
    window.open(whatsappURL, "_blank");

    // 3. Clear cart
    localStorage.removeItem("cart");
    navigate("/thank-you", { state: { orderId } });
  };

  // Place Order
  const placeOrder = async (e) => {
    e.preventDefault();
    const error = validate();
    if (error) return alert(error);

    if (form.paymentMethod === "COD") {
      await saveOrder("Pending");
    } else {
      try {
        // Create Razorpay order
        const { data } = await axios.post("http://localhost:5000/api/payment/create-order", {
          amount: grandTotal,
        });

        const { order, key } = data;

        const options = {
          key,
          amount: order.amount,
          currency: order.currency,
          name: "CREWS Clothing",
          description: "Order Payment",
          order_id: order.id,
          handler: async function (response) {
            const verify = await axios.post("http://localhost:5000/api/payment/verify-payment", {
              razorpay_order_id: response.razorpay_order_id,
              razorpay_payment_id: response.razorpay_payment_id,
              razorpay_signature: response.razorpay_signature,
            });

            if (verify.data.success) {
              await saveOrder("Paid", response.razorpay_payment_id);
            } else {
              alert("Payment verification failed");
            }
          },
          prefill: {
            name: form.name,
            email: form.email,
            contact: form.phone,
          },
          theme: { color: "#3399cc" },
        };

        const rzp = new window.Razorpay(options);
        rzp.open();
      } catch (err) {
        alert("Payment error: " + err.message);
      }
    }
  };

  return cart.length === 0 ? (
    <div className="checkout-empty">
      <h2>Your cart is empty 🛒</h2>
      <Link to="/products" className="btn-link">Continue Shopping</Link>
      <Footer />
    </div>
  ) : (
    <>
      <div className="checkout-container">
        <h2>Checkout</h2>
        <div className="checkout-grid">
          {/* Left */}
          <form className="checkout-form" onSubmit={placeOrder}>
            <h3>Shipping Details</h3>
            <input name="name" value={form.name} onChange={onChange} placeholder="Full Name" />
            <input name="phone" value={form.phone} onChange={onChange} placeholder="Phone" />
            <input name="email" value={form.email} onChange={onChange} placeholder="Email" />
            <textarea name="address" value={form.address} onChange={onChange} placeholder="Address" />
            <input name="city" value={form.city} onChange={onChange} placeholder="City" />
            <input name="pincode" value={form.pincode} onChange={onChange} placeholder="Pincode" />

            <label>Payment</label>
            <label>
              <input type="radio" name="paymentMethod" value="COD" checked={form.paymentMethod==="COD"} onChange={onChange} /> COD
            </label>
            <label>
              <input type="radio" name="paymentMethod" value="ONLINE" checked={form.paymentMethod==="ONLINE"} onChange={onChange} /> Online
            </label>

            <button type="submit" className="place-order-btn">Place Order</button>
          </form>

          {/* Right */}
          <div className="checkout-summary">
            <h3>Summary</h3>
            {cart.map((it) => (
              <div key={it._id + it.selectedSize}>
                <p>{it.name} ({it.quantity}x) - ₹{it.price * it.quantity}</p>
              </div>
            ))}
            <hr />
            <p>Subtotal: ₹{total}</p>
            <p>Delivery: {delivery === 0 ? "FREE" : `₹${delivery}`}</p>
            <h4>Total: ₹{grandTotal}</h4>
          </div>
        </div>
      </div>
      <Footer />
    </>
  );
}

export default Checkout;
